/**
 * React Email component registry definitions for UIBuilder.
 *
 * Install via shadcn CLI:
 *   npx shadcn@latest add https://raw.githubusercontent.com/olliethedev/ui-builder/main/registry/react-email-components-registry.json
 *
 * Usage:
 *   import { reactEmailComponentDefinitions } from "@/lib/ui-builder/registry/react-email-component-definitions";
 *
 *   <UIBuilder
 *     componentRegistry={{ ...reactEmailComponentDefinitions }}
 *     pageTypeRenderers={{ email: emailPageRenderer }}
 *     pageTypeCodeGenerators={{ email: emailCodeGenerator }}
 *   />
 *
 * Tailwind note: React email supports a subset of Tailwind via the <Tailwind> wrapper.
 * Unsupported utilities include: prose (@tailwindcss/typography), space-*, hover: pseudo-class.
 * Media queries work but are only applied in supporting clients.
 * See https://www.caniemail.com for client support details.
 */

import {
  Html,
  Head,
  Body,
  Preview,
  Container,
  Section,
  Row,
  Column,
  Text,
  Button,
  Link,
  Img,
  Hr,
  Tailwind,
} from "@react-email/components";
import { z } from "zod";
import type { ComponentRegistry } from "@/components/ui/ui-builder/types";
import {
  emailClassNameFieldOverrides,
  childrenFieldOverrides,
  childrenAsTextareaFieldOverrides,
} from "@/lib/ui-builder/registry/form-field-overrides";

// ---------------------------------------------------------------------------
// Shared style schema — accepts a plain string (inline style shorthand) or
// an object. We use z.record for the props panel to treat it as freeform JSON.
// ---------------------------------------------------------------------------
const styleSchema = z.record(z.string(), z.any()).optional();

// ---------------------------------------------------------------------------
// Html — root element
// ---------------------------------------------------------------------------
const htmlSchema = z.object({
  lang: z.string().optional().default("en"),
  dir: z.enum(["ltr", "rtl", "auto"]).optional().default("ltr"),
  className: z.string().optional(),
  style: styleSchema,
  children: z.any().optional(),
});

// ---------------------------------------------------------------------------
// Head — email head (contains meta, Font, style tags)
// ---------------------------------------------------------------------------
const headSchema = z.object({});

// ---------------------------------------------------------------------------
// Body — email body
// ---------------------------------------------------------------------------
const bodySchema = z.object({
  className: z.string().optional(),
  style: styleSchema,
  children: z.any().optional(),
});

// ---------------------------------------------------------------------------
// Preview — inbox preview text (hidden, string-only children)
// ---------------------------------------------------------------------------
const previewSchema = z.object({
  children: z.string().optional().default("Email preview text"),
});

// ---------------------------------------------------------------------------
// Tailwind — Tailwind CSS wrapper for email
// Note: wraps email body content; config accepts a Tailwind theme config object
// ---------------------------------------------------------------------------
const tailwindSchema = z.object({
  config: z
    .record(z.string(), z.any())
    .optional()
    .describe(
      "Tailwind config object (without 'content'). Supports theme, plugins, darkMode, etc."
    ),
  children: z.any().optional(),
});

// ---------------------------------------------------------------------------
// Container — centered max-width container (renders as <table>)
// ---------------------------------------------------------------------------
const containerSchema = z.object({
  className: z.string().optional(),
  style: styleSchema,
  children: z.any().optional(),
});

// ---------------------------------------------------------------------------
// Section — semantic content section (renders as <table>)
// ---------------------------------------------------------------------------
const sectionSchema = z.object({
  className: z.string().optional(),
  style: styleSchema,
  children: z.any().optional(),
});

// ---------------------------------------------------------------------------
// Row — table row layout container (renders as <table>); children must be <Column>
// ---------------------------------------------------------------------------
const rowSchema = z.object({
  className: z.string().optional(),
  style: styleSchema,
  children: z.any().optional(),
});

// ---------------------------------------------------------------------------
// Column — table cell (renders as <td>); must be inside <Row>
// ---------------------------------------------------------------------------
const columnSchema = z.object({
  className: z.string().optional(),
  style: styleSchema,
  colSpan: z.number().optional(),
  width: z.union([z.string(), z.number()]).optional(),
  children: z.any().optional(),
});

// ---------------------------------------------------------------------------
// Text — paragraph (renders as <p>)
// ---------------------------------------------------------------------------
const textSchema = z.object({
  className: z.string().optional(),
  style: styleSchema,
  children: z.string().optional().default("Text content"),
});

// ---------------------------------------------------------------------------
// Button — CTA link-button (renders as <a> with Outlook VML padding)
// ---------------------------------------------------------------------------
const buttonSchema = z.object({
  href: z.string().optional().default("https://example.com"),
  target: z.string().optional().default("_blank"),
  className: z.string().optional(),
  style: styleSchema,
  children: z.string().optional().default("Click me"),
});

// ---------------------------------------------------------------------------
// Link — plain anchor link
// ---------------------------------------------------------------------------
const linkSchema = z.object({
  href: z.string().optional().default("https://example.com"),
  target: z.string().optional().default("_blank"),
  className: z.string().optional(),
  style: styleSchema,
  children: z.string().optional().default("Click here"),
});

// ---------------------------------------------------------------------------
// Img — email-safe image (component is named Img, not Image)
// ---------------------------------------------------------------------------
const imgSchema = z.object({
  src: z.string().optional().default("https://placehold.co/600x200"),
  alt: z.string().optional().default(""),
  width: z.union([z.string(), z.number()]).optional(),
  height: z.union([z.string(), z.number()]).optional(),
  className: z.string().optional(),
  style: styleSchema,
});

// ---------------------------------------------------------------------------
// Hr — horizontal rule divider
// ---------------------------------------------------------------------------
const hrSchema = z.object({
  className: z.string().optional(),
  style: styleSchema,
});

// ---------------------------------------------------------------------------
// Registry export
// ---------------------------------------------------------------------------
export const reactEmailComponentDefinitions: ComponentRegistry = {
  Html: {
    component: Html,
    schema: htmlSchema,
    from: "@react-email/components",
    skipEditorWrapper: true,
    defaultChildren: [],
    fieldOverrides: {
      className: emailClassNameFieldOverrides,
      children: childrenFieldOverrides,
    },
  },

  Head: {
    component: Head,
    schema: headSchema,
    from: "@react-email/components",
    skipEditorWrapper: true,
    childOf: ["Html"],
    defaultChildren: [],
  },

  Body: {
    component: Body,
    schema: bodySchema,
    from: "@react-email/components",
    skipEditorWrapper: true,
    childOf: ["Html", "Tailwind"],
    defaultChildren: [],
    fieldOverrides: {
      className: emailClassNameFieldOverrides,
      children: childrenFieldOverrides,
    },
  },

  Preview: {
    component: Preview,
    schema: previewSchema,
    from: "@react-email/components",
    skipEditorWrapper: true,
    childOf: ["Html"],
    defaultChildren: "Email preview text",
    fieldOverrides: {
      children: childrenAsTextareaFieldOverrides,
    },
  },

  Tailwind: {
    component: Tailwind,
    schema: tailwindSchema,
    from: "@react-email/components",
    childOf: ["Html"],
    defaultChildren: [],
    fieldOverrides: {
      children: childrenFieldOverrides,
    },
  },

  Container: {
    component: Container,
    schema: containerSchema,
    from: "@react-email/components",
    defaultChildren: [],
    fieldOverrides: {
      className: emailClassNameFieldOverrides,
      children: childrenFieldOverrides,
    },
  },

  Section: {
    component: Section,
    schema: sectionSchema,
    from: "@react-email/components",
    defaultChildren: [],
    fieldOverrides: {
      className: emailClassNameFieldOverrides,
      children: childrenFieldOverrides,
    },
  },

  Row: {
    component: Row,
    schema: rowSchema,
    from: "@react-email/components",
    childOf: ["Section", "Container", "Column", "Body"],
    defaultChildren: [],
    fieldOverrides: {
      className: emailClassNameFieldOverrides,
      children: childrenFieldOverrides,
    },
  },

  Column: {
    component: Column,
    schema: columnSchema,
    from: "@react-email/components",
    childOf: ["Row"],
    defaultChildren: [],
    fieldOverrides: {
      className: emailClassNameFieldOverrides,
      children: childrenFieldOverrides,
    },
  },

  Text: {
    component: Text,
    schema: textSchema,
    from: "@react-email/components",
    defaultChildren: "Text content",
    fieldOverrides: {
      className: emailClassNameFieldOverrides,
      children: childrenAsTextareaFieldOverrides,
    },
  },

  Button: {
    component: Button,
    schema: buttonSchema,
    from: "@react-email/components",
    defaultChildren: "Click me",
    fieldOverrides: {
      className: emailClassNameFieldOverrides,
      children: childrenAsTextareaFieldOverrides,
    },
  },

  Link: {
    component: Link,
    schema: linkSchema,
    from: "@react-email/components",
    defaultChildren: "Click here",
    fieldOverrides: {
      className: emailClassNameFieldOverrides,
      children: childrenAsTextareaFieldOverrides,
    },
  },

  Img: {
    component: Img,
    schema: imgSchema,
    from: "@react-email/components",
    fieldOverrides: {
      className: emailClassNameFieldOverrides,
    },
  },

  Hr: {
    component: Hr,
    schema: hrSchema,
    from: "@react-email/components",
    fieldOverrides: {
      className: emailClassNameFieldOverrides,
    },
  },
};

"use client";

/**
 * Email builder utilities for UIBuilder consumers.
 *
 * Provides ready-to-use wiring for react-email page type support:
 *  - Canvas-safe substitutes for structural HTML elements
 *  - EmailCanvasRenderer — canvas renderer for email pages
 *  - generateEmailCode — JSX code generator
 *  - emailPageRenderer — PageTypeRenderer config (pass to UIBuilder)
 *  - emailCodeGenerator — PageTypeCodeGenerator config (pass to UIBuilder)
 *
 * UIBuilder itself has zero knowledge of @react-email. All email-specific
 * logic lives here.
 *
 * Usage:
 *   import { emailPageRenderer, emailCodeGenerator } from "@/lib/ui-builder/email/email-builder-utils";
 *   import { reactEmailComponentDefinitions } from "@/lib/ui-builder/registry/react-email-component-definitions";
 *
 *   <UIBuilder
 *     componentRegistry={reactEmailComponentDefinitions}
 *     pageTypeRenderers={{ email: emailPageRenderer }}
 *     pageTypeCodeGenerators={{ email: emailCodeGenerator }}
 *   />
 */

import React, { useMemo } from "react";
import LayerRenderer from "@/components/ui/ui-builder/layer-renderer";
import { pixelBasedPreset } from "@react-email/components";
import type {
  PageTypeRenderer,
  PageTypeCodeGenerator,
  PageTypeRendererProps,
  ComponentLayer,
  ComponentRegistry,
} from "@/components/ui/ui-builder/types";
export { EmailTailwindThemePanel } from "@/lib/ui-builder/email/email-tailwind-theme-panel";

export const DEFAULT_EMAIL_TAILWIND_CONFIG = {
  presets: [pixelBasedPreset],
  theme: {
    extend: {},
  },
};

/**
 * Canvas-safe substitutes for structural HTML elements.
 *
 * React-email components like Html, Head, Body render actual html/head/body DOM
 * elements. When placed inside an iframe's content div those elements are either
 * moved by the browser or rendered invisibly. For the editor canvas we swap them
 * with div/null equivalents so the visual content appears correctly while
 * click-to-select and drag-and-drop still work.
 *
 * The real @react-email components are preserved in the registry for code
 * generation (generateEmailCode uses the original `from` paths and types).
 */
export const NullComponent = () => null;
NullComponent.displayName = "NullComponent";

export const CanvasHtml = ({ children }: { children?: React.ReactNode }) => (
  <div data-email-html style={{ display: "contents" }}>{children}</div>
);
CanvasHtml.displayName = "CanvasHtml";

export const CanvasBody = ({ children, className }: { children?: React.ReactNode; className?: string }) => (
  <div data-email-body className={className} style={{ backgroundColor: "white", minHeight: "100%" }}>{children}</div>
);
CanvasBody.displayName = "CanvasBody";

/**
 * Email canvas renderer.
 * Uses a canvas-specific registry that replaces structural HTML elements
 * (Html, Head, Preview) with safe div/null substitutes so they render
 * correctly inside the AutoFrame iframe.
 */
export function EmailCanvasRenderer({
  page,
  componentRegistry,
  editorConfig,
  variables,
  variableValues,
  functionRegistry,
}: PageTypeRendererProps) {
  const canvasRegistry: ComponentRegistry = useMemo(() => {
    const base = { ...componentRegistry };
    if (base.Html) base.Html = { ...base.Html, component: CanvasHtml };
    if (base.Head) base.Head = { ...base.Head, component: NullComponent };
    if (base.Preview) base.Preview = { ...base.Preview, component: NullComponent };
    if (base.Body) base.Body = { ...base.Body, component: CanvasBody };
    return base;
  }, [componentRegistry]);

  return (
    <LayerRenderer
      className="contents"
      page={page}
      componentRegistry={canvasRegistry}
      editorConfig={editorConfig}
      variables={variables}
      variableValues={variableValues}
      functionRegistry={functionRegistry}
    />
  );
}

/**
 * Email code generator.
 * Generates the JSX component + an example of how to call @react-email/render.
 * This replaces the default "React" tab in the code panel for email pages.
 */
export function generateEmailCode(page: ComponentLayer, registry: ComponentRegistry): string {
  // Map from module path -> set of named exports to import from that module.
  const namedImports = new Map<string, Set<string>>();
  namedImports.set("@react-email/render", new Set(["render"]));

  const collectImports = (layer: ComponentLayer) => {
    const def = registry[layer.type];
    if (def?.from) {
      if (!namedImports.has(def.from)) {
        namedImports.set(def.from, new Set());
      }
      namedImports.get(def.from)!.add(layer.type);
    }
    if (Array.isArray(layer.children)) {
      layer.children.forEach(collectImports);
    }
  };
  collectImports(page);

  const imports = Array.from(namedImports.entries())
    .sort(([a], [b]) => a.localeCompare(b))
    .map(([mod, names]) => `import { ${Array.from(names).sort().join(", ")} } from "${mod}";`);

  const renderLayer = (layer: ComponentLayer, indent = 0): string => {
    const pad = "  ".repeat(indent);
    const propsStr = Object.entries(layer.props)
      // `children` is rendered from `layer.children` to avoid duplicate/conflicting output.
      .filter(([k, v]) => k !== "children" && v !== undefined && v !== null && v !== "")
      .map(([k, v]) => {
        if (typeof v === "string") return `${k}=${JSON.stringify(v)}`;
        return `${k}={${JSON.stringify(v)}}`;
      })
      .join(" ");

    if (Array.isArray(layer.children) && layer.children.length > 0) {
      const childrenStr = layer.children
        .map((child) => renderLayer(child, indent + 1))
        .join("\n");
      return `${pad}<${layer.type}${propsStr ? " " + propsStr : ""}>\n${childrenStr}\n${pad}</${layer.type}>`;
    } else if (typeof layer.children === "string" && layer.children) {
      return `${pad}<${layer.type}${propsStr ? " " + propsStr : ""}>{${JSON.stringify(layer.children)}}</${layer.type}>`;
    }
    return `${pad}<${layer.type}${propsStr ? " " + propsStr : ""} />`;
  };

  const jsx = renderLayer(page, 1);

  return [
    imports.join("\n"),
    "",
    "// Email template component",
    "export function EmailTemplate() {",
    "  return (",
    jsx,
    "  );",
    "}",
    "",
    "// Generate HTML string (use in your email sending service)",
    "export async function renderEmailHtml() {",
    "  const html = await render(<EmailTemplate />);",
    "  return html;",
    "}",
  ].join("\n");
}

/** PageTypeRenderer config for email pages. */
export const emailPageRenderer: PageTypeRenderer = {
  label: "Email",
  defaultRootLayerType: "Html",
  defaultRootLayerProps: { lang: "en" },
  // skipAutoFrame is intentionally omitted so the canvas uses the AutoFrame
  // iframe (which provides style isolation and zoom/pan).
  // EmailCanvasRenderer swaps structural HTML elements with div substitutes
  // so the content renders visibly inside the iframe.
  filterRegistry: (registry) => registry,
  renderEditorCanvas: (props) => <EmailCanvasRenderer {...props} />,
};

/** PageTypeCodeGenerator for email pages. */
export const emailCodeGenerator: PageTypeCodeGenerator = {
  label: "Email JSX",
  generateCode: generateEmailCode,
};

"use client";

import { useCallback, useEffect, useMemo, useState } from "react";
import { pixelBasedPreset } from "@react-email/components";
import { CheckIcon, InfoIcon, MoonIcon, SunIcon } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Label } from "@/components/ui/label";
import { Toggle } from "@/components/ui/toggle";
import {
  baseColors,
  type BaseColor,
} from "@/components/ui/ui-builder/internal/utils/base-colors";
import type { ComponentLayer } from "@/components/ui/ui-builder/types";
import { useLayerStore } from "@/lib/ui-builder/store/layer-store";
import { cn } from "@/lib/utils";

function findFirstTailwindLayer(layer: ComponentLayer | undefined): ComponentLayer | null {
  if (!layer) return null;
  if (layer.type === "Tailwind") return layer;

  if (!Array.isArray(layer.children)) return null;
  for (const child of layer.children) {
    const found = findFirstTailwindLayer(child);
    if (found) return found;
  }
  return null;
}

function asRecord(value: unknown): Record<string, unknown> {
  if (typeof value === "object" && value !== null && !Array.isArray(value)) {
    return value as Record<string, unknown>;
  }
  return {};
}

function getColorTheme(mode: "light" | "dark", colorName: BaseColor["name"]) {
  const color = baseColors.find((item) => item.name === colorName) ?? baseColors[0];
  const vars = color?.cssVars[mode];
  if (!vars) return {};

  return {
    background: `hsl(${vars.background})`,
    foreground: `hsl(${vars.foreground})`,
    card: `hsl(${vars.card})`,
    "card-foreground": `hsl(${vars["card-foreground"]})`,
    popover: `hsl(${vars.popover})`,
    "popover-foreground": `hsl(${vars["popover-foreground"]})`,
    primary: `hsl(${vars.primary})`,
    "primary-foreground": `hsl(${vars["primary-foreground"]})`,
    secondary: `hsl(${vars.secondary})`,
    "secondary-foreground": `hsl(${vars["secondary-foreground"]})`,
    muted: `hsl(${vars.muted})`,
    "muted-foreground": `hsl(${vars["muted-foreground"]})`,
    accent: `hsl(${vars.accent})`,
    "accent-foreground": `hsl(${vars["accent-foreground"]})`,
    destructive: `hsl(${vars.destructive})`,
    border: `hsl(${vars.border})`,
    input: `hsl(${vars.input})`,
    ring: `hsl(${vars.ring})`,
  };
}

export function EmailTailwindThemePanel() {
  const selectedPageId = useLayerStore((state) => state.selectedPageId);
  const updateLayer = useLayerStore((state) => state.updateLayer);
  const findLayerById = useLayerStore((state) => state.findLayerById);

  const selectedPage = findLayerById(selectedPageId) as ComponentLayer | undefined;
  const tailwindLayer = useMemo(
    () => findFirstTailwindLayer(selectedPage),
    [selectedPage]
  );

  const [isCustomTheme, setIsCustomTheme] = useState(false);
  const [colorTheme, setColorTheme] = useState<BaseColor["name"]>("blue");
  const [mode, setMode] = useState<"light" | "dark">("light");
  const [radius, setRadius] = useState(0.5);

  useEffect(() => {
    if (!tailwindLayer) return;
    const layerProps = asRecord(tailwindLayer.props);
    const existingConfig = asRecord(layerProps.config);
    const theme = asRecord(existingConfig.theme);
    const themeExtend = asRecord(theme.extend);
    const hasCustomColors = Boolean(themeExtend.colors);
    setIsCustomTheme(hasCustomColors);
  }, [tailwindLayer]);

  useEffect(() => {
    if (!tailwindLayer) return;

    if (!isCustomTheme) {
      updateLayer(tailwindLayer.id, {
        config: {
          presets: [pixelBasedPreset],
          theme: { extend: {} },
        },
      });
      return;
    }

    const layerProps = asRecord(tailwindLayer.props);
    const existingConfig = asRecord(layerProps.config);
    const existingTheme = asRecord(existingConfig.theme);
    const existingExtend = asRecord(existingTheme.extend);
    const colors = getColorTheme(mode, colorTheme);

    updateLayer(tailwindLayer.id, {
      config: {
        ...existingConfig,
        presets: [pixelBasedPreset],
        theme: {
          ...existingTheme,
          extend: {
            ...existingExtend,
            colors,
            borderRadius: {
              lg: `${radius}rem`,
              md: `calc(${radius}rem - 2px)`,
              sm: `calc(${radius}rem - 4px)`,
            },
          },
        },
      },
    });
  }, [tailwindLayer, isCustomTheme, colorTheme, mode, radius, updateLayer]);

  const handleToggleCustomTheme = useCallback(() => {
    setIsCustomTheme((prev) => !prev);
  }, []);

  if (!tailwindLayer) {
    return (
      <div className="mt-4 text-sm text-muted-foreground flex items-center gap-2">
        <InfoIcon className="size-4" />
        Add a Tailwind layer to enable email theme controls.
      </div>
    );
  }

  return (
    <div className="flex flex-col gap-4 mt-4">
      <Toggle
        variant="outline"
        onPressedChange={handleToggleCustomTheme}
        pressed={isCustomTheme}
      >
        {isCustomTheme ? "Use Default Email Theme" : "Use Custom Email Theme"}
      </Toggle>

      {!isCustomTheme && (
        <span className="flex items-center gap-2 text-sm">
          <InfoIcon className="size-4" /> Using default Tailwind email preset.
        </span>
      )}

      {isCustomTheme && (
        <div className="flex flex-col gap-2">
          <Label className="mt-2">Colors</Label>
          <div className="flex gap-2 flex-wrap">
            {baseColors.map((color) => (
              <Button
                key={color.name}
                variant="outline"
                size="sm"
                className={cn(
                  "gap-2",
                  color.name === colorTheme && "border-primary border-2"
                )}
                onClick={() => setColorTheme(color.name)}
              >
                <div
                  className="size-4 rounded-full"
                  style={{
                    backgroundColor: `hsl(${color.activeColor[mode === "dark" ? "dark" : "light"]})`,
                  }}
                >
                  {color.name === colorTheme && <CheckIcon className="size-4" />}
                </div>
                {color.label}
              </Button>
            ))}
          </div>

          <Label className="mt-2">Border Radius</Label>
          <div className="flex gap-2 flex-wrap">
            {[0.0, 0.15, 0.3, 0.5, 0.75, 1.0].map((value) => (
              <Button
                key={value}
                variant="outline"
                size="sm"
                className={cn("gap-2", radius === value && "border-primary border-2")}
                onClick={() => setRadius(value)}
              >
                {value}
              </Button>
            ))}
          </div>

          <Label className="mt-2">Mode</Label>
          <div className="flex gap-2">
            {(["light", "dark"] as const).map((modeOption) => (
              <Button
                key={modeOption}
                variant="outline"
                size="sm"
                className={cn(mode === modeOption && "border-primary border-2")}
                onClick={() => setMode(modeOption)}
              >
                {modeOption === "light" ? (
                  <SunIcon className="mr-1 -translate-x-1" />
                ) : (
                  <MoonIcon className="mr-1 -translate-x-1" />
                )}
                {modeOption}
              </Button>
            ))}
          </div>
        </div>
      )}
    </div>
  );
}
